// Index with degrees [0..359]; negative wraps automatically
static inline float sin_deg(int d) {
  d = (d % 360 + 360) % 360;
  return sin_lut[d];
}

static inline float cos_deg(int d) {
  d = (d % 360 + 360) % 360;
  return cos_lut[d];
}
